import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Card.module.css';

type CardRootProps = HTMLArkProps<'div'> & {
  size?: 'sm' | 'md' | 'lg';
  variant?: 'elevated' | 'outline' | 'subtle';
};

const CardRoot = forwardRef<HTMLDivElement, CardRootProps>(function CardRoot(
  { className, size = 'md', variant = 'outline', ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="root"
      data-slot="card-root"
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardHeader = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function CardHeader(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="header"
      data-slot="card-header"
      className={clsx(styles.header, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardBody = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function CardBody(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="body"
      data-slot="card-body"
      className={clsx(styles.body, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardMedia = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function CardMedia(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="media"
      data-slot="card-media"
      className={clsx(styles.media, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardFooter = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function CardFooter(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="footer"
      data-slot="card-footer"
      className={clsx(styles.footer, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardTitle = forwardRef<HTMLHeadingElement, HTMLArkProps<'h3'>>(function CardTitle(
  { className, ...props },
  ref,
) {
  return (
    <ark.h3
      ref={ref}
      data-scope="card"
      data-part="title"
      data-slot="card-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardDescription = forwardRef<HTMLParagraphElement, HTMLArkProps<'p'>>(
  function CardDescription({ className, ...props }, ref) {
    return (
      <ark.p
        ref={ref}
        data-scope="card"
        data-part="description"
        data-slot="card-description"
        className={clsx(styles.description, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const CardAction = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function CardAction(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="card"
      data-part="action"
      data-slot="card-action"
      className={clsx(styles.action, normalizeClassName(className))}
      {...props}
    />
  );
});

const CardLink = forwardRef<HTMLAnchorElement, HTMLArkProps<'a'>>(function CardLink(
  { className, ...props },
  ref,
) {
  return (
    <ark.a
      ref={ref}
      data-scope="card"
      data-part="link"
      data-slot="card-link"
      className={clsx(styles.link, normalizeClassName(className))}
      {...props}
    />
  );
});

const Card = Object.assign(CardRoot, {
  Root: CardRoot,
  Header: CardHeader,
  Body: CardBody,
  Media: CardMedia,
  Footer: CardFooter,
  Title: CardTitle,
  Description: CardDescription,
  Action: CardAction,
  Link: CardLink,
});

export { Card };

@layer moduix.components {
  .root {
    --moduix-card-padding-default: var(
      --moduix-card-spacing,
      var(--moduix-card-padding, var(--moduix-spacing-6))
    );
    --moduix-card-section-spacing-default: var(
      --moduix-card-spacing,
      var(--moduix-card-body-padding-top, var(--moduix-spacing-4))
    );
    --moduix-card-title-font-size-default: var(
      --moduix-card-title-font-size,
      var(--moduix-text-lg)
    );
    --moduix-card-title-line-height-default: var(
      --moduix-card-title-line-height,
      var(--moduix-line-height-text-lg)
    );

    box-sizing: border-box;
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    flex-direction: column;
    border: var(
        --moduix-card-border-width,
        var(--moduix-card-border-width-default, var(--moduix-border-width-sm))
      )
      solid var(--moduix-card-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-card-radius, var(--moduix-radius-lg));
    background-color: var(
      --moduix-card-bg,
      var(--moduix-card-bg-default, var(--moduix-color-card))
    );
    color: var(--moduix-card-color, var(--moduix-color-card-foreground));
    box-shadow: var(--moduix-card-shadow, var(--moduix-card-shadow-default, none));

    &:where(a) {
      text-decoration: none;
    }

    &[data-size='sm'] {
      --moduix-card-padding-default: var(
        --moduix-card-spacing-sm,
        var(--moduix-card-spacing, var(--moduix-card-padding-sm, var(--moduix-spacing-4)))
      );
      --moduix-card-section-spacing-default: var(
        --moduix-card-spacing-sm,
        var(--moduix-card-spacing, var(--moduix-card-body-padding-top, var(--moduix-spacing-4)))
      );
      --moduix-card-title-font-size-default: var(
        --moduix-card-title-font-size-sm,
        var(--moduix-text-md)
      );
      --moduix-card-title-line-height-default: var(
        --moduix-card-title-line-height-sm,
        var(--moduix-line-height-text-md)
      );
    }

    &[data-size='lg'] {
      --moduix-card-padding-default: var(
        --moduix-card-spacing-lg,
        var(--moduix-card-spacing, var(--moduix-card-padding-lg, var(--moduix-spacing-8)))
      );
      --moduix-card-section-spacing-default: var(
        --moduix-card-spacing-lg,
        var(--moduix-card-spacing, var(--moduix-card-body-padding-top, var(--moduix-spacing-4)))
      );
      --moduix-card-title-font-size-default: var(
        --moduix-card-title-font-size-lg,
        var(--moduix-text-xl)
      );
      --moduix-card-title-line-height-default: var(
        --moduix-card-title-line-height-lg,
        var(--moduix-line-height-text-xl)
      );
    }

    &[data-variant='elevated'] {
      --moduix-card-border-width-default: 0;
      --moduix-card-shadow-default: var(--moduix-shadow-md);
    }

    &[data-variant='subtle'] {
      --moduix-card-border-width-default: 0;
      --moduix-card-bg-default: var(--moduix-color-muted);
    }

    &:has([data-scope='card'][data-part='link'])
      :where(
        a,
        button,
        input,
        select,
        textarea,
        [role='button'],
        [role='checkbox'],
        [role='menuitem'],
        [role='switch'],
        [tabindex]:not([tabindex='-1'])
      ):not([data-scope='card'][data-part='link']) {
      position: relative;
      z-index: 1;
    }
  }

  .header,
  .body,
  .footer {
    box-sizing: border-box;
    min-width: 0;
    padding-inline: var(--moduix-card-padding-default);
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    column-gap: var(--moduix-card-action-gap, var(--moduix-spacing-2));
    row-gap: var(--moduix-card-header-gap, var(--moduix-spacing-1));
    padding-block: var(--moduix-card-padding-default) 0;
  }

  .media {
    min-width: 0;
    overflow: hidden;
    border-start-start-radius: inherit;
    border-start-end-radius: inherit;

    & > :where(img, picture, video, canvas, svg, iframe) {
      display: block;
      width: 100%;
      max-width: 100%;
    }
  }

  .body {
    padding-block: var(--moduix-card-section-spacing-default) var(--moduix-card-padding-default);
    color: var(--moduix-card-body-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-card-body-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-card-body-line-height, var(--moduix-line-height-text-sm));
    overflow-wrap: anywhere;

    &:first-child {
      padding-block-start: var(--moduix-card-padding-default);
    }

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .footer {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--moduix-card-footer-gap, var(--moduix-spacing-2));
    padding-block: 0 var(--moduix-card-padding-default);
  }

  .title {
    grid-column: 1;
    margin: 0;
    min-width: 0;
    color: var(--moduix-card-title-color, currentColor);
    font-size: var(--moduix-card-title-font-size-default);
    font-weight: var(--moduix-card-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-card-title-line-height-default);
    overflow-wrap: anywhere;
  }

  .description {
    grid-column: 1;
    margin: 0;
    min-width: 0;
    color: var(--moduix-card-description-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-card-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-card-description-line-height, var(--moduix-line-height-text-sm));
    overflow-wrap: anywhere;
  }

  .action {
    position: relative;
    z-index: 1;
    grid-column: 2;
    grid-row: 1 / span 2;
    display: inline-flex;
    align-items: start;
    justify-content: flex-end;
    gap: var(--moduix-card-action-gap, var(--moduix-spacing-2));
    justify-self: end;
  }

  .link {
    position: static;
    color: inherit;
    text-decoration: none;

    &::after {
      content: '';
      position: absolute;
      z-index: 0;
      inset: 0;
      border-radius: var(--moduix-card-radius, var(--moduix-radius-lg));
    }

    &:focus-visible {
      outline: 0;
    }

    &:focus-visible::after {
      outline: var(
          --moduix-card-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-card-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-card-focus-ring-offset, var(--moduix-border-width-sm));
    }
  }
}
